
.meter {
  display: grid;
  gap: 5px;
}

.meter-heading {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  font-size: 0.82rem;
}

.meter-heading strong {
  color: var(--accent-primary-strong);
  font-family: var(--font-data);
  font-size: 1rem;
}

.meter-heading small {
  color: var(--ink-muted);
  font-size: 0.66rem;
  font-weight: 400;
}

.meter-track {
  height: 9px;
  padding: 1px;
  border: 1px solid var(--line-strong);
  background: var(--surface-raised);
}

.meter-fill {
  display: block;
  height: 100%;
  background: var(--accent-primary);
  transition: width 240ms ease;
}

.meter-caption {
  color: var(--ink-muted);
  font-size: 0.72rem;
}

@media (prefers-reduced-motion: reduce) {
  .meter-fill {
    transition: none;
  }
}
